    { id: "night", label: "夜間", time: "18:00–21:00", hours: 3 },
]

/** 1週間の日付列 */
export interface DayDef {
    id: string
    /** 例: 「6/23」 */
    label: string
    /** 例: 「月」 */
    weekday: string
    /** 休館日（施設点検・年末年始など） */
