// --- 計算ロジック（手書きは data.ts に隔離） ------------------------------

/** 室料 × 時間帯（時間数）× 利用区分 を合算した1コマの料金。 */
export function computeFee(roomId: string, slotId: SlotId, categoryId: UsageCategoryId): number {
    const room = ROOMS.find((r) => r.id === roomId)
    const slot = TIME_SLOTS.find((s) => s.id === slotId)
    const category = USAGE_CATEGORIES.find((c) => c.id === categoryId)
    if (!room || !slot || !category) return 0
    return Math.round(room.hourlyRate * slot.hours * category.rate)
}

export function reservationStatus(r: Reservation): ReservationStatus {
    if (r.workflowStatus === "rejected") return "rejected"
    if (r.workflowStatus === "approved") return "confirmed"
    return "pending"
}

/**
 * 重複防止：確定（承認済み）予約が同一 室×日×時間帯 に2件以上ある、または
 * 確定済みと同じ枠に申請中が重なっているケースを検出する。
 */
export function findConflicts(reservations: Reservation[]): Map<string, Reservation[]> {
    const byCell = new Map<string, Reservation[]>()
    for (const r of reservations) {
        if (r.workflowStatus === "rejected") continue
        const key = `${r.roomId}::${r.dayId}::${r.slotId}`
        const list = byCell.get(key) ?? []
        list.push(r)
        byCell.set(key, list)
    }
    const conflicts = new Map<string, Reservation[]>()
    for (const [key, list] of byCell) {
        if (list.length > 1) conflicts.set(key, list)
    }
    return conflicts
}

export function roomName(roomId: string): string {
    return ROOMS.find((r) => r.id === roomId)?.name ?? roomId
}

export function categoryLabel(id: UsageCategoryId): string {
    return USAGE_CATEGORIES.find((c) => c.id === id)?.label ?? id
}

export function slotLabel(id: SlotId): string {
    const s = TIME_SLOTS.find((s) => s.id === id)
    return s ? `${s.label}（${s.time}）` : id
}

export function dayLabel(id: string): string {
    const d = WEEK_DAYS.find((d) => d.id === id)
    return d ? `${d.label}（${d.weekday}）` : id
}

"use client"

import * as React from "react"
import {
    Container,
    Card,
    CardHeader,
    CardTitle,
    CardDescription,
    CardContent,
    ScheduleGrid,
    type ScheduleCell,
    type ScheduleAxisItem,
    Statistic,
    Badge,
    Select,
    Separator,
    Alert,
    AlertTitle,
    AlertDescription,
    DataTable,
    type ColumnDef,
    formatCurrency,
    type WorkflowValue,
} from "@gunjo/ui"
import {
    IconBuildingCommunity,
    IconAlertTriangle,
    IconCalendarStats,
} from "@tabler/icons-react"

import {
    ROOMS,
    WEEK_DAYS,
    TIME_SLOTS,
    INITIAL_RESERVATIONS,
    USAGE_CATEGORIES,
    computeFee,
    findConflicts,
    reservationStatus,
    roomName,
    slotLabel,
    dayLabel,
    categoryLabel,
    type Reservation,
    type SlotId,
    type StageId,
    type UsageCategoryId,
    type ReservationStatus,
} from "./data"
import { STATUS_META } from "./status"
import { ReservationSheet } from "./ReservationSheet"

const ACTOR = "山田（管理係）"

export function FacilityBooking() {
    const [reservations, setReservations] = React.useState<Reservation[]>(INITIAL_RESERVATIONS)
    const [roomId, setRoomId] = React.useState<string>(ROOMS[0].id)
    const [selectedId, setSelectedId] = React.useState<string | null>(null)
    const [sheetOpen, setSheetOpen] = React.useState(false)

    const conflicts = React.useMemo(() => findConflicts(reservations), [reservations])

    const conflictingIds = React.useMemo(() => {
        const ids = new Set<string>()
        for (const list of conflicts.values()) {
            for (const r of list) ids.add(r.id)
        }
        return ids
    }, [conflicts])

    // 選択中の施設の予約だけをグリッドに反映
    const cellByKey = React.useMemo(() => {
        const map = new Map<string, Reservation>()
        for (const r of reservations) {
            if (r.roomId !== roomId) continue
            // 同一セルに複数（重複）あるときは、確定 > 申請中 の優先で代表を表示
            const key = `${r.slotId}::${r.dayId}`
            const existing = map.get(key)
            if (!existing || rank(r) > rank(existing)) map.set(key, r)
        }
        return map
    }, [reservations, roomId])

    const openReservation = React.useCallback((id: string) => {
        setSelectedId(id)
        setSheetOpen(true)
    }, [])

    const handleWorkflowChange = React.useCallback((id: string, next: WorkflowValue) => {
        setReservations((prev) =>
            prev.map((r) =>
                r.id === id
                    ? {
                          ...r,
                          currentStageId: next.currentStageId as StageId,
                          workflowStatus: next.status ?? "in-progress",
                          records: (next.records ?? {}) as Reservation["records"],
                      }
                    : r
            )
        )
    }, [])

    const handleCategoryChange = React.useCallback((id: string, categoryId: UsageCategoryId) => {
        setReservations((prev) => prev.map((r) => (r.id === id ? { ...r, categoryId } : r)))
    }, [])

    const selected = reservations.find((r) => r.id === selectedId) ?? null

    // --- ScheduleGrid 用の軸・セル ---------------------------------------
    const rows: ScheduleAxisItem[] = TIME_SLOTS.map((s) => ({
        id: s.id,
        label: s.label,
        sublabel: s.time,
    }))

    const columns: ScheduleAxisItem[] = WEEK_DAYS.map((d) => ({
        id: d.id,
        label: d.weekday,
        sublabel: d.label,
        ariaLabel: `${d.label} ${d.weekday}曜日`,
    }))

    const cells: ScheduleCell[] = []
    for (const slot of TIME_SLOTS) {
        for (const day of WEEK_DAYS) {
            if (day.closed) {
                cells.push({
                    rowId: slot.id,
                    colId: day.id,
                    unavailable: true,
                })
                continue
            }
            const key = `${slot.id}::${day.id}`
            const r = cellByKey.get(key)
            if (!r) continue // 空きセルは renderEmpty に任せる
            const status = reservationStatus(r)
            const meta = STATUS_META[status]
            const conflicting = conflictingIds.has(r.id)
            const StatusIcon = meta.icon
            cells.push({
                rowId: slot.id,
                colId: day.id,
                tone: conflicting ? "destructive" : meta.tone,
                onSelect: () => openReservation(r.id),
                description: `${meta.label}、${r.group}${conflicting ? "、重複あり" : ""}`,
                content: (
                    <span className="flex flex-col gap-1">
                        <span className="inline-flex items-center gap-1 text-[11px] font-semibold">
                            <StatusIcon className="h-3 w-3 shrink-0" aria-hidden />
                            {meta.label}
                            {conflicting ? (
                                <IconAlertTriangle className="h-3 w-3 shrink-0 text-destructive" aria-hidden />
                            ) : null}
                        </span>
                        <span className="line-clamp-2 text-xs leading-tight">{r.group}</span>
                    </span>
                ),
            })
        }
    }

    // --- KPI -------------------------------------------------------------
    const pendingCount = reservations.filter((r) => reservationStatus(r) === "pending").length
    const confirmedCount = reservations.filter((r) => reservationStatus(r) === "confirmed").length
    const weeklyRevenue = reservations
        .filter((r) => reservationStatus(r) === "confirmed")
        .reduce((sum, r) => sum + computeFee(r.roomId, r.slotId, r.categoryId), 0)
    const closedReason = WEEK_DAYS.find((d) => d.closed)?.closedReason

    const selectedRoom = ROOMS.find((r) => r.id === roomId)

    return (
        <main className="min-h-screen bg-background py-6 sm:py-10">
            <Container className="flex flex-col gap-6">
                {/* ヘッダー */}
                <header className="flex flex-col gap-2">
                    <p className="inline-flex items-center gap-1.5 text-sm font-medium text-muted-foreground">
                        <IconBuildingCommunity className="h-4 w-4" aria-hidden />
                        みどり市民センター ／ 貸館予約管理
                    </p>
                    <h1 className="text-2xl font-bold tracking-tight sm:text-3xl">
                        公共施設 予約管理
                    </h1>
                    <p className="text-sm text-muted-foreground">
                        週間の予約状況の確認、利用申請の承認、料金計算までを一画面で行います。
                    </p>
                </header>

                {/* KPI */}
                <section aria-label="予約サマリー" className="grid grid-cols-2 gap-3 lg:grid-cols-4">
                    <Statistic label="承認待ち（申請中）" value={`${pendingCount} 件`} hint="要対応" />
                    <Statistic label="予約確定" value={`${confirmedCount} 件`} hint="許可書発行済み含む" />
                    <Statistic
                        label="今週の利用料金（確定分）"
                        value={formatCurrency(weeklyRevenue)}
                        hint="納付予定額"
                    />
                    <Statistic
                        label="重複（要解消）"
                        value={`${conflicts.size} 件`}
                        trend={conflicts.size > 0 ? "up" : "flat"}
                        tone={conflicts.size > 0 ? "negative" : "neutral"}
                        hint="ダブルブッキング検出"
                    />
                </section>

                {/* 重複アラート */}
                {conflicts.size > 0 ? (
                    <Alert variant="destructive">
                        <IconAlertTriangle aria-hidden />
                        <AlertTitle as="h2">予約枠の重複が {conflicts.size} 件あります</AlertTitle>
                        <AlertDescription>
                            {Array.from(conflicts.values()).map((list) => {
                                const head = list[0]
                                return (
                                    <span key={`${head.roomId}-${head.dayId}-${head.slotId}`} className="block">
                                        {roomName(head.roomId)}・{dayLabel(head.dayId)}・{slotLabel(head.slotId)}：
                                        {list.map((r) => r.group).join(" / ")}
                                    </span>
                                )
                            })}
                        </AlertDescription>
                    </Alert>
                ) : null}

                {/* 予約グリッド */}
                <Card>
                    <CardHeader className="gap-3">
                        <div className="flex flex-wrap items-end justify-between gap-3">
                            <div className="flex flex-col gap-1">
                                <CardTitle as="h2" className="inline-flex items-center gap-2 text-lg">
                                    <IconCalendarStats className="h-5 w-5" aria-hidden />
                                    予約グリッド（時間帯 × 日付）
                                </CardTitle>
                                <CardDescription>
                                    施設を選ぶと、その週の空き状況が表示されます。セルを選択すると申請内容と承認操作を開けます。
                                </CardDescription>
                            </div>
                            <div className="w-full sm:w-64">
                                <Select
                                    label="施設・部屋"
                                    value={roomId}
                                    onChange={(event) => setRoomId(event.target.value)}
                                >
                                    {ROOMS.map((r) => (
                                        <option key={r.id} value={r.id}>
                                            {r.name}（定員 {r.capacity}名 / 室料 {formatCurrency(r.hourlyRate)}/h）
                                        </option>
                                    ))}
                                </Select>
                            </div>
                        </div>
                        <Legend />
                    </CardHeader>
                    <CardContent>
                        <ScheduleGrid
                            label={`${selectedRoom?.name ?? ""} の週間予約グリッド`}
                            cornerLabel="時間帯"
                            rows={rows}
                            columns={columns}
                            cells={cells}
                            minColumnWidth={104}
                            rowHeaderWidth={84}
                            unavailableLabel="休館"
                            renderEmpty={() => (
                                <span className="inline-flex items-center gap-1 text-xs text-muted-foreground">
                                    <STATUS_META.available.icon className="h-3 w-3" aria-hidden />
                                    空き
                                </span>
                            )}
                        />
                        {closedReason ? (
                            <p className="mt-3 text-xs text-muted-foreground">
                                ※ 休館：{dayLabel(WEEK_DAYS.find((d) => d.closed)!.id)} — {closedReason}
                            </p>
                        ) : null}
                    </CardContent>
                </Card>

                {/* 予約一覧 */}
                <Card>
                    <CardHeader>
                        <CardTitle as="h2" className="text-lg">
                            予約・申請一覧
                        </CardTitle>
                        <CardDescription>
                            全施設の申請。行を選択すると詳細と承認フローを開きます。
                        </CardDescription>
                    </CardHeader>
                    <CardContent>
                        <ReservationTable
                            reservations={reservations}
                            conflictingIds={conflictingIds}
                            onRowClick={(r) => openReservation(r.id)}
                        />
                    </CardContent>
                </Card>
            </Container>

            <ReservationSheet
                reservation={selected}
                open={sheetOpen}
                onOpenChange={setSheetOpen}
                onWorkflowChange={handleWorkflowChange}
                onCategoryChange={handleCategoryChange}
                isConflicting={selected ? conflictingIds.has(selected.id) : false}
                actor={ACTOR}
            />
        </main>
    )
}

function rank(r: Reservation): number {
    const s = reservationStatus(r)
    return s === "confirmed" ? 3 : s === "pending" ? 2 : 1
}

// --- 凡例（色だけに頼らない状態表示） -------------------------------------
function Legend() {
    const items: { status: ReservationStatus | "closed" }[] = [
        { status: "available" },
        { status: "pending" },
        { status: "confirmed" },
        { status: "rejected" },
        { status: "closed" },
    ]
    return (
        <div className="flex flex-wrap items-center gap-2" aria-label="凡例">
            <span className="text-xs font-medium text-muted-foreground">凡例：</span>
            {items.map(({ status }) => {
                const meta = STATUS_META[status]
                const Icon = meta.icon
                return (
                    <Badge key={status} variant={meta.badgeVariant} icon={<Icon />}>
                        {meta.label}
                    </Badge>
                )
            })}
        </div>
    )
}

