function ReservationTable({
    reservations,
    conflictingIds,
    onRowClick,
}: {
    reservations: Reservation[]
    conflictingIds: Set<string>
    onRowClick: (r: Reservation) => void
}) {
    const columns = React.useMemo<ColumnDef<Reservation>[]>(
        () => [
            {
                accessorFn: (r) => roomName(r.roomId),
                id: "room",
                header: "施設・部屋",
                cell: ({ row }) => (
                    <div className="flex flex-col">
                        <span className="font-medium">{roomName(row.original.roomId)}</span>
                        <span className="text-xs text-muted-foreground">
                            {dayLabel(row.original.dayId)}・{slotLabel(row.original.slotId)}
                        </span>
                    </div>
                ),
            },
            {
                accessorKey: "group",
                header: "団体・申請者",
                cell: ({ row }) => (
                    <div className="flex flex-col">
                        <span className="font-medium">{row.original.group}</span>
                        <span className="text-xs text-muted-foreground">{row.original.applicant}</span>
                    </div>
                ),
            },
            {
                accessorFn: (r) => categoryLabel(r.categoryId),
                id: "category",
                header: "利用区分",
                cell: ({ row }) => (
                    <span className="text-sm">{categoryLabel(row.original.categoryId)}</span>
                ),
            },
            {
                accessorFn: (r) => computeFee(r.roomId, r.slotId, r.categoryId),
                id: "fee",
                header: "料金",
                cell: ({ row }) => (
                    <span className="tabular-nums">
                        {formatCurrency(computeFee(row.original.roomId, row.original.slotId, row.original.categoryId))}
                    </span>
                ),
            },
            {
                accessorFn: (r) => reservationStatus(r),
                id: "status",
                header: "状態",
                cell: ({ row }) => {
                    const status = reservationStatus(row.original)
