            data={reservations}
            pageSize={10}
            onRowClick={onRowClick}
            filter={{ columnId: "group", placeholder: "団体名で絞り込み…" }}
            labels={{
                filterPlaceholder: "団体名で絞り込み…",
                noResults: "該当する予約がありません。",
                rowsPerPage: "表示件数",
                paginationSummary: (from, to, total) => `${total} 件中 ${from}–${to} 件`,
                pageSummary: (cur, totalPages) => `${cur} / ${totalPages} ページ`,
                previous: "前へ",
                next: "次へ",
                firstPage: "最初のページ",
                lastPage: "最後のページ",
                sortAscending: "クリックで昇順に並べ替え",
                sortDescending: "クリックで降順に並べ替え",
                clearSort: "クリックで並べ替えを解除",
                sortUnsorted: "現在：未ソート",
                sortCurrentAscending: "現在：昇順",
                sortCurrentDescending: "現在：降順",
                goToPage: (page) => `${page} ページへ`,
                pageSelect: "ページを選択",
            }}
            renderCard={(r) => {
                const status = reservationStatus(r)
                const meta = STATUS_META[status]
                const Icon = meta.icon
                const conflicting = conflictingIds.has(r.id)
                return (
                    <div className="flex flex-col gap-2">
                        <div className="flex items-start justify-between gap-2">
                            <div className="flex flex-col">
                                <span className="font-semibold">{r.group}</span>
                                <span className="text-xs text-muted-foreground">{r.applicant}</span>
                            </div>
                            <div className="flex shrink-0 flex-wrap justify-end gap-1">
                                <Badge variant={meta.badgeVariant} icon={<Icon />}>
                                    {meta.label}
                                </Badge>
                                {conflicting ? (
                                    <Badge variant="destructive" icon={<IconAlertTriangle />}>
                                        重複
                                    </Badge>
                                ) : null}
                            </div>
                        </div>
                        <Separator />
                        <div className="grid grid-cols-2 gap-x-3 gap-y-1 text-xs">
                            <span className="text-muted-foreground">施設</span>
                            <span className="text-right">{roomName(r.roomId)}</span>
                            <span className="text-muted-foreground">日時</span>
                            <span className="text-right">
                                {dayLabel(r.dayId)}・{slotLabel(r.slotId)}
                            </span>
                            <span className="text-muted-foreground">区分</span>
                            <span className="text-right">{categoryLabel(r.categoryId)}</span>
                            <span className="text-muted-foreground">料金</span>
                            <span className="text-right tabular-nums">
                                {formatCurrency(computeFee(r.roomId, r.slotId, r.categoryId))}
                            </span>
                        </div>
                    </div>
                )
            }}
        />
    )
}

"use client"

import * as React from "react"
import {
    Sheet,
    SheetContent,
    SheetHeader,
    SheetTitle,
    SheetDescription,
    ApprovalWorkflow,
    type WorkflowValue,
    Badge,
    MetadataList,
    Separator,
    Statistic,
    Alert,
    AlertTitle,
    AlertDescription,
    Select,
    formatCurrency,
} from "@gunjo/ui"
import {
    IconUsers,
    IconBuildingCommunity,
    IconCalendarEvent,
    IconClock,
    IconReceiptYen,
    IconAlertTriangle,
} from "@tabler/icons-react"

import {
    APPROVAL_STAGES,
    USAGE_CATEGORIES,
    computeFee,
    roomName,
    slotLabel,
    dayLabel,
    categoryLabel,
    type Reservation,
    type UsageCategoryId,
} from "./data"
import { STATUS_META } from "./status"

export interface ReservationSheetProps {
    reservation: Reservation | null
    open: boolean
    onOpenChange: (open: boolean) => void
    /** 承認フローの状態更新（誰が・いつを記録） */
    onWorkflowChange: (id: string, next: WorkflowValue) => void
    /** 利用区分の変更（料金が再計算される） */
    onCategoryChange: (id: string, categoryId: UsageCategoryId) => void
    /** この予約が他の確定予約と重複しているか */
    isConflicting: boolean
    actor: string
}

export function ReservationSheet({
    reservation,
    open,
    onOpenChange,
    onWorkflowChange,
    onCategoryChange,
    isConflicting,
    actor,
}: ReservationSheetProps) {
    return (
        <Sheet open={open} onOpenChange={onOpenChange}>
            <SheetContent
                side="right"
                closeLabel="閉じる"
                className="flex w-full flex-col gap-0 overflow-y-auto sm:max-w-md"
            >
                {reservation ? (
                    <ReservationSheetBody
                        reservation={reservation}
                        onWorkflowChange={onWorkflowChange}
                        onCategoryChange={onCategoryChange}
                        isConflicting={isConflicting}
                        actor={actor}
                    />
                ) : (
                    <SheetHeader>
                        <SheetTitle>予約が選択されていません</SheetTitle>
                    </SheetHeader>
                )}
            </SheetContent>
        </Sheet>
    )
}

function ReservationSheetBody({
    reservation,
    onWorkflowChange,
    onCategoryChange,
    isConflicting,
    actor,
}: {
    reservation: Reservation
    onWorkflowChange: (id: string, next: WorkflowValue) => void
    onCategoryChange: (id: string, categoryId: UsageCategoryId) => void
    isConflicting: boolean
    actor: string
}) {
    const fee = computeFee(reservation.roomId, reservation.slotId, reservation.categoryId)
    const statusMeta =
        reservation.workflowStatus === "approved"
            ? STATUS_META.confirmed
            : reservation.workflowStatus === "rejected"
              ? STATUS_META.rejected
              : STATUS_META.pending
    const StatusIcon = statusMeta.icon

    const workflowValue: WorkflowValue = {
        currentStageId: reservation.currentStageId,
        status: reservation.workflowStatus,
        records: reservation.records,
    }

    return (
        <>
            <SheetHeader className="text-left">
                <div className="flex flex-wrap items-center gap-2">
                    <SheetTitle>{reservation.group}</SheetTitle>
                    <Badge variant={statusMeta.badgeVariant} icon={<StatusIcon />}>
                        {statusMeta.label}
                    </Badge>
                </div>
                <SheetDescription>
                    申請番号 {reservation.id.toUpperCase()} ／ 申請者 {reservation.applicant}
                </SheetDescription>
            </SheetHeader>

            <div className="mt-4 flex flex-col gap-5">
                {isConflicting ? (
                    <Alert variant="destructive">
                        <IconAlertTriangle aria-hidden />
                        <AlertTitle as="h3">予約枠が重複しています</AlertTitle>
                        <AlertDescription>
                            同じ {roomName(reservation.roomId)}・{dayLabel(reservation.dayId)}・
                            {slotLabel(reservation.slotId)} に別の予約があります。承認すると
                            ダブルブッキングになるため、いずれかを差戻し／却下してください。
                        </AlertDescription>
                    </Alert>
                ) : null}

                {/* 予約の基本情報 */}
                <section aria-labelledby="reservation-detail-heading">
                    <h3 id="reservation-detail-heading" className="sr-only">
                        予約の詳細
                    </h3>
                    <MetadataList
                        items={[
                            {
                                label: "施設・部屋",
                                value: roomName(reservation.roomId),
                                icon: <IconBuildingCommunity size={16} aria-hidden />,
                            },
                            {
                                label: "利用日",
                                value: dayLabel(reservation.dayId),
                                icon: <IconCalendarEvent size={16} aria-hidden />,
                            },
                            {
                                label: "時間帯",
                                value: slotLabel(reservation.slotId),
                                icon: <IconClock size={16} aria-hidden />,
                            },
                            {
                                label: "利用人数",
                                value: `${reservation.headcount} 名`,
                                icon: <IconUsers size={16} aria-hidden />,
                            },
                            {
                                label: "利用目的",
                                value: reservation.purpose,
                            },
                        ]}
                    />
                </section>

                <Separator />

                {/* 利用区分・料金 */}
                <section aria-labelledby="fee-heading" className="flex flex-col gap-3">
                    <h3 id="fee-heading" className="text-sm font-semibold">
                        利用区分・料金
                    </h3>
                    <Select
                        label="利用区分"
                        description="区分により室料に減免・割増が適用されます。"
                        value={reservation.categoryId}
                        onChange={(event) =>
                            onCategoryChange(reservation.id, event.target.value as UsageCategoryId)
                        }
                    >
                        {USAGE_CATEGORIES.map((c) => (
                            <option key={c.id} value={c.id}>
                                {c.label}（{c.note}）
                            </option>
                        ))}
                    </Select>
                    <Statistic
                        label={
                            <span className="inline-flex items-center gap-1">
                                <IconReceiptYen size={14} aria-hidden />
                                利用料金（室料 × 時間帯 × {categoryLabel(reservation.categoryId)}）
                            </span>
                        }
                        value={formatCurrency(fee)}
                        hint="納付確認後に許可書を発行します。"
                    />
                </section>

                <Separator />

                {/* 承認フロー */}
                <section aria-labelledby="workflow-heading" className="flex flex-col gap-3">
                    <h3 id="workflow-heading" className="text-sm font-semibold">
                        承認フロー
                    </h3>
                    <ApprovalWorkflow
                        stages={APPROVAL_STAGES.map((s) => ({ id: s.id, label: s.label, name: s.name }))}
                        value={workflowValue}
                        onChange={(next) => onWorkflowChange(reservation.id, next)}
                        actor={actor}
                        canAdvance={!isConflicting}
                        advanceHint={
                            isConflicting ? "重複している予約があるため先に解消してください" : undefined
                        }
                        labels={{
                            advance: "次の段階へ",
                            finish: "許可書を発行",
                            sendBack: "差戻し",
                            reject: "却下",
                            sendBackTarget: "差戻し先の段階",
                            reason: "理由・コメント",
                            reasonPlaceholder: "差戻し／却下の理由を入力…",
                            completed: "承認完了・許可書発行済み",
                            rejected: "この申請は却下されました",
                        }}
                        stateLabels={{
                            pending: "未着手",
                            current: "対応中",
                            approved: "完了",
                            rejected: "却下",
                            skipped: "省略",
                        }}
                    />
                </section>
            </div>
        </>
    )
}

import {
    IconCircleCheck,
    IconClockHour4,
    IconCircleX,
    IconCircleDashed,
    IconLock,
    type IconProps,
} from "@tabler/icons-react"
import type { BadgeProps } from "@gunjo/ui"
import type { ScheduleCellTone } from "@gunjo/ui"
import type { ReservationStatus } from "./data"

type TablerIcon = React.ForwardRefExoticComponent<
    IconProps & React.RefAttributes<SVGSVGElement>
>

export interface StatusMeta {
    label: string
    /** 状態を色だけに頼らず示すアイコン（凡例・バッジ・グリッド共通） */
    icon: TablerIcon
    badgeVariant: NonNullable<BadgeProps["variant"]>
    /** ScheduleGrid のセル色調 */
    tone: ScheduleCellTone
}

/**
 * 予約状態 → ラベル + アイコン + バッジ配色 + グリッドのトーン。
 * 色覚に依存しないよう、必ずアイコンとテキストを併記する。
 */
export const STATUS_META: Record<
    ReservationStatus | "closed",
    StatusMeta
> = {
    available: {
        label: "空き",
        icon: IconCircleDashed,
        badgeVariant: "outline",
        tone: "default",
    },
    pending: {
        label: "申請中",
        icon: IconClockHour4,
        badgeVariant: "warning",
        tone: "warning",
    },
    confirmed: {
        label: "予約済",
        icon: IconCircleCheck,
        badgeVariant: "success",
        tone: "success",
    },
    rejected: {
        label: "却下",
        icon: IconCircleX,
        badgeVariant: "destructive",
        tone: "muted",
    },
    closed: {
        label: "休館",
        icon: IconLock,
        badgeVariant: "secondary",
        tone: "muted",
    },
}
